1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! `SYS_FORK` — clone a blocked parent into a free process slot.
4	//!
5	//! PM owns the process tree; the kernel's half of fork is mechanical
6	//! (MINIX 3 `kernel/system/do_fork.c`): validate, copy the parent's saved
7	//! state into the child slot PM picked, give the child its own address space
8	//! (an eager page-by-page copy — CoW is deferred), and hand back the child's
9	//! endpoint. PM then drives `VM_FORK`, `SCHEDULING_START`, and the
10	//! `SYS_PRIVCTL(PRIVCTL_SET_USER)` release before replying to both halves.
11	//!
12	//! The parent must be RECEIVE-blocked with no pending delivery ("fork is done
13	//! synchronously", MINIX parity): in the live flow it is mid-`SENDREC` to PM,
14	//! so its full register frame is parked in `Proc::regs` with `x0` already
15	//! holding the SENDREC's `OK`. The child copies that frame *verbatim* — both
16	//! processes resume after the same `svc` instruction and read their own reply
17	//! buffer; PM's reply `m_type` (child pid vs 0) is the only discriminator,
18	//! not a patched return register.
19	//!
20	//! The child is created **frozen**: `RTS_RECEIVING` (a faithful mid-SENDREC
21	//! receiver, so PM's reply delivers normally) plus `RTS_NO_PRIV` (the
22	//! stub-E freeze gate — `SYS_PRIVCTL` releases it once VM and SCHED know
23	//! about the child). It is not enqueued; `rts_unset` admits it when the last
24	//! block bit clears. `priv_id` is inherited from the parent — the shared
25	//! `USER_PRIV_ID` slot (MINIX's `static_priv` model), which is what lets PM's
26	//! reply pass `mini_send`'s `ipc_to` check before the release.
27	//!
28	//! The child consumes the slot's **stored** endpoint rather than minting one:
29	//! `SYS_EXIT` bumped the generation when it freed the slot, so a recycled
30	//! slot's new occupant is unreachable through any stale endpoint.
31	//!
32	//! Target-taking (routed beside `SYS_EXIT` in `kernel_call_dispatch`); trust
33	//! model identical to `do_vmctl` — the `k_call_mask` gate is the only check,
34	//! and PM is the intended sole holder.
35	//!
36	//! ## Message payload layout (offsets within `Message::payload`)
37	//!
38	//! | offset | field                  | direction |
39	//! |--------|------------------------|-----------|
40	//! |  0..4  | parent endpoint (i32)  | in        |
41	//! |  4..8  | child proc nr (i32)    | in        |
42	//! |  0..4  | child endpoint (i32)   | out       |
43	
44	use core::fmt::Write;
45	use core::sync::atomic::{AtomicU64, Ordering};
46	
47	use minixrs_kernel_shared::ProcNr;
48	use minixrs_kernel_shared::com::NR_PROCS;
49	use minixrs_kernel_shared::endpoint::NONE;
50	use minixrs_kernel_shared::error::{EINVAL, ENOMEM, OK};
51	use minixrs_kernel_shared::message::Message;
52	
53	use crate::arch::aarch64::addrspace::{AddrSpace, MapError, walk_leaves};
54	use crate::arch::aarch64::asid;
55	use crate::arch::aarch64::mmu::flush_icache_range;
56	use crate::mm::{FRAME_SIZE, Frame, alloc_frame, free_frame, phys_to_hhdm};
57	use crate::proc::flags::{
58	    MF_DELIVERMSG, MF_REPLY_PEND, RTS_NO_PRIV, RTS_RECEIVING, RTS_SENDING, RTS_SLOT_FREE,
59	};
60	use crate::proc::table::{N_PROC_SLOTS, proc_index};
61	use crate::proc::{PageFaultState, Proc};
62	use crate::uart::Uart;
63	
64	/// Leading `SYS_FORK` calls traced explicitly, plus an every-100th steady
65	/// sample — same cadence as `do_exit`'s trace, its lifecycle twin.
66	const FORK_TRACE_HEAD: u64 = 6;
67	const FORK_TRACE_EVERY: u64 = 100;
68	static FORK_COUNT: AtomicU64 = AtomicU64::new(0);
69	
70	/// `SYS_FORK` — clone `parent` into the free slot `child_nr`; reply the
71	/// child's endpoint.
72	pub(super) fn do_fork(
73	    proc_table: &mut [Proc; N_PROC_SLOTS],
74	    caller_nr: ProcNr,
75	    msg: &mut Message,
76	) -> i32 {
77	    let parent_e = read_i32(msg, 0);
78	    let child_nr_raw = read_i32(msg, 4);
79	
80	    let parent_idx = match super::resolve_target(proc_table, caller_nr, parent_e) {
81	        Ok(idx) => idx,
82	        Err(e) => return e,
83	    };
84	
85	    // The child slot is named by proc nr, not endpoint — it is free, so it
86	    // has no live endpoint to validate. Task slots (negative) are never
87	    // forkable.
88	    if !(0..NR_PROCS as i32).contains(&child_nr_raw) {
89	        return EINVAL;
90	    }
91	    let child_nr = ProcNr::new(child_nr_raw);
92	    let child_idx = proc_index(child_nr).expect("user proc nr in range");
93	    if proc_table[child_idx].rts_flags.load(Ordering::Relaxed) & RTS_SLOT_FREE == 0 {
94	        return EINVAL;
95	    }
96	
97	    // Parent gate: RECEIVE-blocked (mid-SENDREC to PM in the live flow) with
98	    // its frame fully parked and no delivery half-done. MINIX 3 do_fork.c:
99	    // "make sure the parent is blocked waiting for the reply".
100	    let parent = &proc_table[parent_idx];
101	    let parent_rts = parent.rts_flags.load(Ordering::Relaxed);
102	    if parent_rts & RTS_RECEIVING == 0
103	        || parent_rts & RTS_SENDING != 0
104	        || parent.misc_flags & MF_DELIVERMSG != 0
105	    {
106	        return EINVAL;
107	    }
108	    if parent.ttbr0_pa == 0 {
109	        // A proc with no address space (kernel task, never-loaded server)
110	        // has nothing to clone.
111	        return EINVAL;
112	    }
113	
114	    // Build the child's address space *before* touching the child slot, so a
115	    // mid-copy allocation failure needs no proc-table rollback.
116	    let child_as = match copy_addrspace(parent.ttbr0_pa) {
117	        Ok((ttbr0_pa, pages)) => (ttbr0_pa, pages),
118	        Err(_) => return ENOMEM,
119	    };
120	    let (child_ttbr0, pages) = child_as;
121	
122	    // SAFETY: single-threaded EL1 context; sole accessor of the ASID pool.
123	    let child_asid = unsafe { asid::alloc_asid() };
124	
125	    // Snapshot the parent fields the child inherits (ends the shared borrow
126	    // before the child slot is borrowed mutably).
127	    let p = &proc_table[parent_idx];
128	    let parent_regs = p.regs;
129	    let parent_priority = p.priority;
130	    let parent_quantum_ms = p.quantum_ms;
131	    let parent_getfrom_e = p.getfrom_e;
132	    let parent_deliver_msg_vir = p.deliver_msg_vir;
133	    let parent_heap_window = p.heap_window;
134	    let parent_priv_id = p.priv_id;
135	    let parent_name = p.name;
136	    let parent_reply_pend = p.misc_flags & MF_REPLY_PEND;
137	
138	    let child_e = {
139	        let c = &mut proc_table[child_idx];
140	        // Inherited: the parent's exact resume state and identity-adjacent
141	        // fields.
142	        c.regs = parent_regs;
143	        c.priv_id = parent_priv_id;
144	        c.misc_flags = parent_reply_pend;
145	        c.priority = parent_priority;
146	        c.quantum_ms = parent_quantum_ms;
147	        c.quantum_left = parent_quantum_ms as u64;
148	        c.getfrom_e = parent_getfrom_e;
149	        c.deliver_msg_vir = parent_deliver_msg_vir;
150	        c.heap_window = parent_heap_window;
151	        c.name = fork_name(parent_name);
152	        // Fresh: everything that must not leak across the fork (or across the
153	        // slot's previous occupant).
154	        c.user_time = 0;
155	        c.sys_time = 0;
156	        c.alarm_at = 0;
157	        c.sig_pending = 0;
158	        c.caller_q = None;
159	        c.q_link = None;
160	        c.sendto_e = NONE;
161	        c.send_msg = Message {
162	            m_source: 0,
163	            m_type: 0,
164	            payload: [0; 96],
165	        };
166	        c.deliver_msg = Message {
167	            m_source: 0,
168	            m_type: 0,
169	            payload: [0; 96],
170	        };
171	        c.ttbr0_pa = child_ttbr0;
172	        c.asid = child_asid;
173	        c.page_fault_state = PageFaultState::EMPTY;
174	        c.scheduler = NONE; // SCHED claims the child at SCHEDULING_START
175	        c.next_ready = None;
176	        // Blocked exactly like the parent (RECEIVE, waiting on PM's reply)
177	        // plus the freeze gate PM lifts via SYS_PRIVCTL once VM and SCHED
178	        // know about the child. Not enqueued — `rts_unset` admits it when
179	        // the last bit clears.
180	        c.rts_flags
181	            .store(RTS_RECEIVING | RTS_NO_PRIV, Ordering::Relaxed);
182	        c.endpoint // the slot's stored, generation-bumped endpoint
183	    };
184	
185	    write_i32(msg, 0, child_e);
186	
187	    let n = FORK_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
188	    if n <= FORK_TRACE_HEAD || n.is_multiple_of(FORK_TRACE_EVERY) {
189	        let _ = writeln!(
190	            Uart::new(),
191	            "[ksys SYS_FORK] parent={} nr={} child_nr={child_nr_raw} child_e={child_e:#x} pages={pages}",
192	            parent_name[0] as char,
193	            proc_table[parent_idx].nr.get(),
194	        );
195	    }
196	    OK
197	}
198	
199	/// Eagerly clone every mapped page of the tree rooted at `parent_ttbr0` into
200	/// a fresh address space: allocate a frame per leaf, copy the 4 KiB through
201	/// HHDM, and map it at the same VA with the parent's permissions (I-cache
202	/// synced for executable pages — TCG hides a missing flush, real hardware
203	/// does not). Returns `(child_ttbr0_pa, pages_copied)`.
204	///
205	/// On failure the partial child is unwound — its leaves freed, its tree
206	/// destroyed — so an out-of-memory fork leaks nothing.
207	fn copy_addrspace(parent_ttbr0: u64) -> Result<(u64, u64), MapError> {
208	    let mut child = AddrSpace::new()?;
209	    let mut pages: u64 = 0;
210	
211	    let result = walk_leaves(parent_ttbr0, &mut |va, pa, prot| {
212	        let frame = alloc_frame().ok_or(MapError::OutOfMemory)?;
213	        let new_pa = frame.addr();
214	        // SAFETY: both PAs came from the frame allocator, so both are
215	        // HHDM-mapped, 4 KiB-aligned, and distinct (copy_nonoverlapping's
216	        // contract). Single-threaded EL1 context.
217	        unsafe {
218	            core::ptr::copy_nonoverlapping(
219	                phys_to_hhdm(pa) as *const u8,
220	                phys_to_hhdm(new_pa),
221	                FRAME_SIZE,
222	            );
223	        }
224	        if prot.executable {
225	            // SAFETY: the HHDM alias of `new_pa` is a valid EL1-readable
226	            // mapping of the just-written range (same pattern as
227	            // `userland::build_stub`'s blob install).
228	            unsafe { flush_icache_range(phys_to_hhdm(new_pa) as u64, FRAME_SIZE) };
229	        }
230	        if let Err(e) = child.map_page(va, new_pa, prot) {
231	            // `map_page` can OOM allocating an intermediate table *after* the
232	            // leaf frame is already live but before it is linked into the
233	            // tree. The `Err` unwind below sweeps only *mapped* leaves, so
234	            // free this orphan here — otherwise a fork that runs out of
235	            // memory mid-copy would leak exactly this frame.
236	            free_frame(frame);
237	            return Err(e);
238	        }
239	        pages += 1;
240	        Ok(())
241	    });
242	
243	    match result {
244	        Ok(()) => Ok((child.ttbr0_pa, pages)),
245	        Err(e) => {
246	            // Unwind: free the pages the partial copy installed, then the
247	            // tree. The child never had an ASID, so there is nothing to
248	            // flush or recycle.
249	            let _ = walk_leaves(child.ttbr0_pa, &mut |_va, pa, _prot| {
250	                free_frame(Frame::from_addr(pa));
251	                Ok(())
252	            });
253	            child.destroy();
254	            Err(e)
255	        }
256	    }
257	}
258	
259	/// The child's name: the parent's with `*F` appended when there is room
260	/// (MINIX 3 do_fork.c parity — `name[0]` keeps the parent's letter so traces
261	/// stay readable).
262	fn fork_name(
263	    mut name: [u8; crate::proc::proc_struct::PROC_NAME_LEN],
264	) -> [u8; crate::proc::proc_struct::PROC_NAME_LEN] {
265	    let len = name.iter().position(|&b| b == 0).unwrap_or(name.len());
266	    if len + 2 < name.len() {
267	        name[len] = b'*';
268	        name[len + 1] = b'F';
269	    }
270	    name
271	}
272	
273	#[inline]
274	fn read_i32(msg: &Message, off: usize) -> i32 {
275	    i32::from_ne_bytes(
276	        msg.payload[off..off + 4]
277	            .try_into()
278	            .expect("payload in range"),
279	    )
280	}
281	
282	#[inline]
283	fn write_i32(msg: &mut Message, off: usize, v: i32) {
284	    msg.payload[off..off + 4].copy_from_slice(&v.to_ne_bytes());
285	}
