3	//! Kernel-call numbers — the `m_type` values for `SENDREC`s addressed to the
4	//! `SYSTEM` task.
5	//!
6	//! Numbering convention follows MINIX 3 `include/minix/com.h` (`KERNEL_CALL`
7	//! base, contiguous offsets). Only the 14 calls needed by Phase 2 are
8	//! defined; more are added as later phases come online.
9	
10	/// Base for kernel-call numbers. Matches MINIX 3 `KERNEL_CALL`.
11	pub const KERNEL_CALL: i32 = 0x600;
12	
13	#[allow(clippy::identity_op)] // explicit `+ 0` keeps the table aligned visually
14	pub const SYS_GETINFO: i32 = KERNEL_CALL + 0;
15	pub const SYS_PRIVCTL: i32 = KERNEL_CALL + 1;
16	pub const SYS_FORK: i32 = KERNEL_CALL + 2;
17	pub const SYS_EXEC: i32 = KERNEL_CALL + 3;
18	pub const SYS_EXIT: i32 = KERNEL_CALL + 4;
19	pub const SYS_COPY: i32 = KERNEL_CALL + 5;
20	pub const SYS_SAFECOPY: i32 = KERNEL_CALL + 6;
21	pub const SYS_IRQCTL: i32 = KERNEL_CALL + 7;
22	pub const SYS_VMCTL: i32 = KERNEL_CALL + 8;
23	pub const SYS_SCHEDULE: i32 = KERNEL_CALL + 9;
24	pub const SYS_SETALARM: i32 = KERNEL_CALL + 10;
25	pub const SYS_TIMES: i32 = KERNEL_CALL + 11;
26	pub const SYS_DIAGCTL: i32 = KERNEL_CALL + 12;
27	pub const SYS_SETGRANT: i32 = KERNEL_CALL + 13;
28	/// Scheduler claim/release. A user-space scheduler (SCHED) calls this to take a
29	/// target proc under its management (`target.scheduler = caller`) or hand it
30	/// back to the kernel scheduler (`SCHEDCTL_FLAG_KERNEL`). Made real in slice 4.3
31	/// alongside `SYS_SCHEDULE`; payload layout mirrors `SYS_VMCTL` (flags in
32	/// `0..4`, target endpoint in `4..8`).
33	pub const SYS_SCHEDCTL: i32 = KERNEL_CALL + 14;
34	/// Raise a signal on a target proc (slice 4.5). Target endpoint in payload
35	/// `0..4` (i32), signal number in `4..8` (i32, `1..NSIG`). The kernel records
36	/// the signal in the target's pending bitmap (`cause_sig`) and notifies PM,
37	/// which drains via `SYS_GETKSIG` / `SYS_ENDKSIG`. This is the MINIX 3
38	/// non-PM-caller semantics (queue toward PM); PM's own direct-delivery branch
39	/// (`send_sig` to a system proc) is deferred until a consumer exists.
40	pub const SYS_KILL: i32 = KERNEL_CALL + 15;
41	/// PM → kernel: fetch the next proc with pending kernel signals (slice 4.5).
42	/// Reply payload: target endpoint in `0..4` (i32; `NONE` when nothing is
43	/// pending) and the pending-signal bitmap in `4..8` (u32). The kernel hands
44	/// the bitmap off (clears `Proc::sig_pending`) but leaves the target's
45	/// signal-pending RTS state set until `SYS_ENDKSIG` acknowledges it.
46	pub const SYS_GETKSIG: i32 = KERNEL_CALL + 16;
47	/// PM → kernel: signal processing for the target (payload `0..4`, i32) is
48	/// complete — clear its signal-pending RTS state (slice 4.5).
49	pub const SYS_ENDKSIG: i32 = KERNEL_CALL + 17;
50	
51	/// `SYS_SCHEDCTL` flag: revert the target to kernel scheduling
52	/// (`target.scheduler = NONE`). Absent → the caller claims the target as its
53	/// own scheduler. Matches MINIX 3 `SCHEDCTL_FLAG_KERNEL` (`include/minix/com.h`).
54	pub const SCHEDCTL_FLAG_KERNEL: i32 = 1 << 0;
55	
56	/// Number of kernel calls defined through Phase 4. Slice 4.3 made
57	/// `SYS_SCHEDULE` real and added `SYS_SCHEDCTL` (15); slice 4.5 adds the
58	/// signal trio `SYS_KILL` / `SYS_GETKSIG` / `SYS_ENDKSIG`, bringing the
59	/// count to 18.
60	pub const NR_KERN_CALLS_PHASE4: usize = 18;
61	
62	/// Size of the privilege-table kernel-call mask, in bits. Sized as a single
